        void OnPlayerDisconnected(BasePlayer player)
        {
            if (!configData.global.killOnDisconnect)
                return;

            var playerVehicles = storedData.GetPlayerVehicles(player.userID);
            if (playerVehicles == null || playerVehicles.Count == 0)
